import React, { useState } from 'react';
import { UserCircle, Camera, Save, CheckCircle2, AlertCircle, Loader } from 'lucide-react';
import api from '../../services/api';

const StaffProfile = () => {
  const storedName = localStorage.getItem('fullName') || '';
  const storedUser = localStorage.getItem('username') || '';

  const [fullName, setFullName] = useState(storedName);
  const [saving, setSaving]     = useState(false);
  const [success, setSuccess]   = useState('');
  const [error, setError]       = useState('');

  const initials = (name = '') =>
    name.split(' ').map(w => w[0]).slice(0, 2).join('').toUpperCase() || 'S';

  const handleSave = async (e) => {
    e.preventDefault();
    setSaving(true); setSuccess(''); setError('');
    try {
      await api.put('/auth/profile', { fullName });
      localStorage.setItem('fullName', fullName);
      setSuccess('Profile updated successfully!');
    } catch {
      setError('Failed to update profile. Please try again.');
    } finally {
      setSaving(false);
    }
  };

  return (
    <div className="max-w-2xl space-y-5">
      <div className="bg-gradient-to-r from-slate-700 to-slate-900 rounded-2xl p-6 text-white shadow-lg">
        <div className="flex items-center gap-3">
          <UserCircle className="w-6 h-6" />
          <div>
            <h1 className="text-2xl font-bold">My Profile</h1>
            <p className="text-slate-300 text-sm">Manage your personal information</p>
          </div>
        </div>
      </div>

      <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6 space-y-6">
        {/* Avatar section */}
        <div className="flex items-center gap-5">
          <div className="relative">
            <div className="w-20 h-20 rounded-2xl bg-gradient-to-br from-emerald-400 to-green-600 flex items-center justify-center text-white font-bold text-2xl shadow-lg">
              {initials(fullName || storedName)}
            </div>
            <button className="absolute -bottom-1 -right-1 w-7 h-7 bg-white rounded-full border-2 border-slate-200 flex items-center justify-center shadow hover:bg-slate-50 transition-colors">
              <Camera className="w-3.5 h-3.5 text-slate-500" />
            </button>
          </div>
          <div>
            <p className="font-bold text-slate-800 text-lg">{fullName || 'Staff User'}</p>
            <p className="text-slate-400 text-sm">@{storedUser}</p>
            <span className="inline-block mt-1 px-2.5 py-0.5 bg-emerald-100 text-emerald-700 text-xs font-medium rounded-full">Staff</span>
          </div>
        </div>

        {/* Alerts */}
        {success && (
          <div className="flex items-center gap-2 p-3 bg-green-50 border border-green-200 rounded-xl text-green-700 text-sm">
            <CheckCircle2 className="w-4 h-4 flex-shrink-0" /> {success}
          </div>
        )}
        {error && (
          <div className="flex items-center gap-2 p-3 bg-red-50 border border-red-200 rounded-xl text-red-700 text-sm">
            <AlertCircle className="w-4 h-4 flex-shrink-0" /> {error}
          </div>
        )}

        {/* Form */}
        <form onSubmit={handleSave} className="space-y-4">
          <div>
            <label className="block text-sm font-semibold text-slate-700 mb-1.5">Username</label>
            <input
              value={storedUser} disabled
              className="w-full px-4 py-2.5 border border-slate-200 rounded-xl text-sm text-slate-400 bg-slate-50 cursor-not-allowed"
            />
            <p className="text-xs text-slate-400 mt-1">Username cannot be changed</p>
          </div>
          <div>
            <label className="block text-sm font-semibold text-slate-700 mb-1.5">Full Name</label>
            <input
              value={fullName} onChange={e => setFullName(e.target.value)}
              placeholder="Enter your full name"
              className="w-full px-4 py-2.5 border border-slate-200 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-emerald-400 focus:border-transparent"
            />
          </div>
          <div className="pt-2">
            <button
              type="submit" disabled={saving || !fullName.trim()}
              className="flex items-center gap-2 px-6 py-2.5 bg-gradient-to-r from-emerald-600 to-green-500 text-white font-semibold text-sm rounded-xl hover:from-emerald-700 hover:to-green-600 disabled:opacity-60 disabled:cursor-not-allowed transition-all shadow-lg shadow-emerald-200"
            >
              {saving ? <Loader className="w-4 h-4 animate-spin" /> : <Save className="w-4 h-4" />}
              {saving ? 'Saving…' : 'Save Changes'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default StaffProfile;
